/**
 *
 *  @class BxTextarea
 *  @desc BxTextarea 클래스 생성자
 *  @example
 *
 *   <script>
 *
 *       window.textAreaMethod = {
 *
 *          onMaxLength: function(){
 *              console.log('call onMaxLength');
 *          },
 *
 *          onRender: function(){
 *              console.log('call onRender');
 *          },
 *
 *          onClick: function(){
 *              console.log('call onClick');
 *          },
 *
 *          onMouseDown: function(){
 *              console.log('call onMouseDown');
 *          },
 *
 *          onKeyDown: function(){
 *              console.log('call onKeyDown');
 *          }
 *      }
 *
 *      $().ready(function(){
 *
 *          $().BxTextarea().initialize();
 *
 *          var test = document.getElementById('textarea');
 *
 *          // prop 접근 법
 *          console.log(test.maxLength);
 *          console.log(test.background);
 *          console.log(test.enableLimitText);
 *          console.log(test.shape);
 *          console.log(test.label);
 *          console.log(test.inactive);
 *
 *          console.log(test.bxmaxLength);
 *          console.log(test.bxrender);
 *
 *          test.bxmaxLength = function(){
 *              // code ...
 *          }
 *
 *          test.bxrender = function(){
 *              // code ...
 *          }
 *
 *          // API 사용 법
 *          test.indexOf([str]);
 *          test.getLength();
 *          test.getByte();
 *          test.reset();
 *
 *      });
 *
 *  </script>
 *
 *  <bx-textarea id="textarea"
 *               name="test"
 *               placeholder="글을 입력해주세요."
 *               cols="100"
 *               rows="15"
 *               enableLimitText="true"
 *               shape="round"
 *               label="화면식별자1"
 *               bx-maxLength="textAreaMethod.onMaxLength"
 *               bx-render="textAreaMethod.onRender"
 *               bx-click="textAreaMethod.onClick"
 *               bx-Mousedown="textAreaMethod.onMouseDown"
 *               bx-Keydown="textAreaMethod.onKeyDown"
 *               >
 *              [defaultValue]
 *  </bx-textarea>
 *
 */

const BXUI = require('../../../bx-ui-core/entry');
const $ = require('jquery');
const _ = require('lodash');

const BASE = require('../base');
const {Console: CONSOLE, Util: UTIL, Type: TYPE} = BXUI;

// declare TextArea Class
const TEXTAREA_SELECTOR = {
    "bxTextArea": 'bx-textarea',
    "bxInputWrap" : 'bx-input-wrap',
    "disabled": 'disabled',
    "focus": 'focus',
    "bxTextAreaWrap": 'bx-textarea-wrap',
    "single": 'single',
    "charLimit": "char-limit",
    "lineStyle": 'line-style',
    "overflow": 'overflow',
    "ie": 'ie'
};


const ERR_MSG = {
    "notSupportNativeEvent": 'native method 인 on Event 에 대해 제공하지 않습니다. bx Event 를 사용하세요.',
    "setAPI": '_setAPI 의 인자값이 올바르지 않습니다.',
    "setKeyBoardEvent": '_setKeyBoardEvent 의 인자값이 올바르지 않습니다.',
    "refreshCurrentLength": '_refreshCurrentLength 의 인자값이 올바르지 않습니다.'
};

const BACKGROUND_TYPE = {
    "plain": 'plain',
    "line": 'line'
};

const SHAPE_TYPE = {
    "default": 'default',
    "round": 'round',
    "line": 'line'
};

const DEFAULT_MAX_LENGTH = {
    "modern": -1,
    "ie": 2147483647
};

const OPTS = {
    /**
     * @property {object} bx-textarea
     * @property {string} [bx-textarea.shape=default] - <span class='important'>readonly</span> - textarea 의 디자인 타입 (default, round, line)
     * @property {string} [bx-textarea.label=''] - <span class='important'>readonly</span> - label 의 text 값
     * @property {boolean} [bx-textarea.inactive=false] - 비활성화 여부
     * @property {int} [bx-textarea.maxLength] - textarea 엘리먼트의 최대 길이
     * @property {string} [bx-textarea.placeholder=''] - textarea placeholder<br/> <span class='important'>ie9은 readonly 속성으로 지원</span>
     * @property {string} [bx-textarea.background=plain] - <span class='important'>readonly</span> - textarea 엘리먼트의 배경 [plain, line]
     * @property {boolean} [bx-textarea.enableLimitText=false] - <span class='important'>readonly</span> - 현재 / 최대 길이값을 나타내는 영역 표시 여부
     * @property {Function} [bx-textarea.bx-maxLength=function(){}] - 최대 길이 설정시, maxLength 와 동일 시 호출되는 callback 함수
     * @property {Function} [bx-textarea.bx-render=function(){}] - 렌더링 종료 후, 호출되는 callback 함수
     * @property {Function} [bx-textarea.bx-[eventName]=function(){}] - eventName(click, focus 등) 에 해당되는, 네이티브 이벤트를 바인딩시킨다.
     * @alias Attributes
     *
     * @memberOf BxTextarea
     */
    "shape": 'default',
    "label": '',
    "inactive": false,
    "background": 'plain',
    "enableLimitText": false,
    /**
     * @property {function} [bx-maxlength=function(){}] - 최대 길이 설정시, maxLength 와 동일 시 호출되는 callback 함수
     * @callback bx-maxLength
     * @readonly
     * @memberOf BxTextarea
     */
    "bx-maxLength": function(){},
    /**
     * @property {function} [bx-render=function(){}] - 렌더링 종료 후, 호출되는 callback 함수
     * @callback bx-render
     *
     * @readonly
     * @memberOf BxTextarea
     */
    "bx-render": function(){}
};

const READONLY_ATTRS = ['shape', 'label', 'maxLength', 'background', 'enableLimitText'];

// compare attrs name
const ATTR_NAMES = {
    "maxlength": 'maxLength',
    "enablelimittext": 'enableLimitText',
    "bx-maxlength": 'bx-maxLength'
};

// declare APIS
const APIS = {
    "indexOf": _indexOf,
    "getLength": _getLength,
    "getByte": _getByte,
    "reset": _reset
};


class BxTextarea {

    constructor(){
        this.opts = OPTS;
    }

    /**
     * 초기화 함수
     *
     * <p>
     *     DOM이 생성된 이후 (DOM Ready) 초기화 함수를 호출한다.
     * </p>
     * @returns {object} 생성된 인스턴스
     */
    initialize($compile = null, $scope = null){

        // @deprecated
        if (!_.isNull($compile)) {
            CONSOLE.prop.throw(BxTextarea, '$compile', 'deprecatedParameter');
        }

        // @deprecated
        if (!_.isNull($scope)) {
            CONSOLE.prop.throw(BxTextarea, '$scope', 'deprecatedParameter');
        }

        let $textAreas = this.$root.find(TEXTAREA_SELECTOR.bxTextArea);

        this.elems = [];

        _.forEach($textAreas, (v, k) => {

            let $elem = $(v);

            const $container = _parseCustomElement($elem);

            this.elems.push($container.get(0));

        });

        return this;
    }
}

/**
 *
 * Custom Element 를 구별하기위한 플래그
 *
 * `커스텀 엘리먼트`의 경우에는 반드시 아래 프로퍼티값을 정의해야한다.
 *
 * @private
 * @type {boolean}
 */
BxTextarea.isCustomElement = true;


/**
 * custom 태그를 native 태그로 치환한다.
 *
 * @param {object} custom jquery element
 *
 * @private
 * @memberOf BxInput
 */
function _parseCustomElement($customElem = null){

    if (_.isNull($customElem)){
        CONSOLE.prop.throw(BxTextarea, '$customElem', 'type');
    }

    if (!_.isFunction($customElem.get) && !_.isPlainObject($customElem)){
        CONSOLE.prop.throw(BxTextarea, '$customElem', 'type');
    }

    let $container = BASE.appendContainerElement(BxTextarea.$root, BxTextarea.className);

    let opts = _createComponentOptions($customElem, OPTS);

    let $component = _createComponentElement($customElem, opts);

    let $elem = $component.find(`.${TEXTAREA_SELECTOR.bxTextArea}`);
    let elem = $elem.get(0);

    $container.append($component);
    $customElem.replaceWith($container);

    // native event 바인드
    UTIL.addAllEventListenerWithProperty($elem, opts.events);

    _setElementProperties($elem, opts);

    // 컴포넌트별 이벤트를 바인딩한다.
    _init($container);

    _setAPI($elem);

    _setInactive($elem, opts.inactive);

    elem.bxrender.call(elem);

    return $container;
}

/**
 * 컴포넌트 엘리먼트를 생성한다.
 *
 * @param {object} $elem - 엘리먼트 객체
 * @param {object} opts - 컴포넌트 옵션
 *
 * @returns {object} 생성된 컴포넌트 엘리먼트
 *
 * @private
 */
function _createComponentElement($elem = null, opts = {}){


    let html = [];

    let shape = opts.shape;
    let label = opts.label;
    let inactive = opts.inactive;

    let maxLength = UTIL.isIE9() ? opts.maxLength : opts.attr.maxLength;

    let background = opts.background;
    let enableLimitText = opts.enableLimitText;
    let isDefaultMaxLength = _isDefaultMaxLength(maxLength);

    // custom 엘리먼트 내부 Text Value
    let value = _getValue($elem);
    let length = value.length;

    let inputWrapLineStyle = shape === 'default' ? TEXTAREA_SELECTOR.lineStyle : shape;
    let single = !label && enableLimitText ? TEXTAREA_SELECTOR.single : '';
    let disabled = inactive ? TEXTAREA_SELECTOR.disabled : '';

    let bxTextAreaWrapLineStyle = background === 'line' ? TEXTAREA_SELECTOR.lineStyle : '';

    let overflow = !isDefaultMaxLength && (length > maxLength) ? TEXTAREA_SELECTOR.overflow : '';
    let ie = UTIL.isIE() ? TEXTAREA_SELECTOR.ie : '';

    if (opts.attr.class){
        opts.attr.class = `${TEXTAREA_SELECTOR.bxTextArea} ${opts.attr.class}`;
    }
    else{
        opts.attr.class = TEXTAREA_SELECTOR.bxTextArea;
    }

    let attr = UTIL.objectToStringAttr(opts.attr);

    html.push(`<div class="${TEXTAREA_SELECTOR.bxInputWrap} ${inputWrapLineStyle} ${single} ${disabled}">`);

    if (label) {
        html.push(`<label class="bx-label" for="${opts.attr.id}">${label}</label>`);
    }

    html.push(`<div class="${TEXTAREA_SELECTOR.bxTextAreaWrap} ${bxTextAreaWrapLineStyle} ${overflow}">`);
    html.push(`<textarea ${attr}>`);

    if (length > 0) html.push(value);

    html.push('</textarea>');

    if (enableLimitText) {

        html.push(`<div class="${TEXTAREA_SELECTOR.charLimit} ${ie}">`);
        html.push(`<span>${length}</span>`);
        html.push(`/`);
        html.push(`<span>${isDefaultMaxLength ? '-' : maxLength}</span>`);
        html.push('</div>');
    }

    html.push('</div>');
    html.push('</div>');

    return $(html.join(''));
}


/**
 * 컴포넌트 옵션을 생성한다.
 *
 * @param {object} $elem - 바인딩될 엘리먼트 객체
 * @param {object} opts - 컴포넌트 옵션
 * @param {array} attrNames - ie9 을 위한, 어트리뷰트 집합
 *
 * @returns {object} 옵션 객체
 *
 * @private
 */
function _createComponentOptions($elem = null, opts = {}){

    opts = UTIL.createComponentOptions($elem, opts, ATTR_NAMES, (k, v) => {

        if (k === 'shape'){

            if (_.isUndefined(SHAPE_TYPE[v])){
                CONSOLE.prop.throw(BxTextarea, k, 'value');
            }
        }

        if (k === 'background'){

            if (_.isUndefined(BACKGROUND_TYPE[v])){
                CONSOLE.prop.throw(BxTextarea, k, 'value');
            }
        }


        if (k === 'enableLimitText' || k === 'inactive') {

            if (!_.isBoolean(v)){
                CONSOLE.prop.throw(BxTextarea, k, 'type');
            }
        }

        return v;

    }, (k, v) => {

        if (k === 'maxLength'){

            if (!TYPE.isNumber(v)){
                CONSOLE.prop.throw(BxTextarea, k, 'type');
            }
        }

        return v;
    });

    return _setMandatoryOPTS(opts);
}

/**
 * 컴포넌트 프로퍼티를 바인딩 시킨다.
 *
 * @param {object} $elem - 바인딩될 엘리먼트 객체
 * @param {object} opts - 컴포넌트 옵션
 *
 * @returns {object} 생성된 인스턴스
 *
 * @private
 */
function _setElementProperties($elem = null, opts = {}){

    let elem = $elem.get(0);

    _.map(opts, (v, k) => {

        // attr 속성은 무시한다.
        if (k === 'attr') return;
        // events 속성은 무시한다.
        if (k === 'events') return;

        if (k.match(/^bx-/)){

            let _k = k.replace('-', '');

            delete opts[k];

            k = _k;
        }

        // 읽기 전용 속성
        if (_.indexOf(READONLY_ATTRS, k) > -1){
            UTIL.setReadOnlyProperty(elem, k, v);
            return;
        }

        let _k = UTIL.convertInternalPropertyName(k);

        elem[_k] = v;

        UTIL.setPropertyWithDescriptor(elem, k, {
            configurable: true,
            enumerable: true,
            get: function () {
                return this[_k];
            },
            set: function (v) {

                if (k === 'maxLength') {

                    if (!TYPE.isNumber(v) || v <= 1) {
                        CONSOLE.prop.throw(BxTextarea, k, 'all');
                    }

                    _refreshCurrentLength($elem);
                }

                if (k === 'inactive') {

                    if (!_.isBoolean(v)) {
                        CONSOLE.prop.throw(BxTextarea, k, 'type');
                    }

                    _setInactive($elem, v);
                }

                elem[_k] = v;
            }
        });
    });

    return this;
}

/**
 *
 * 이벤트 핸들러 바인딩 함수
 *
 * @param {object} $container - 엘리먼트 객체
 * @param {object} opts - 컴포넌트 옵션
 *
 *
 * @returns 생성된 인스턴스 객체
 *
 * @private
 */
function _init($elem = null) {

    const $bxInputWrap = $elem.find(`.${TEXTAREA_SELECTOR.bxInputWrap}`);
    const $bxTextAreaWrap = $elem.find(`.${TEXTAREA_SELECTOR.bxTextAreaWrap}`);
    const $textArea = $elem.find(`.${TEXTAREA_SELECTOR.bxTextArea}`);

    const maxLength = $textArea.prop('maxLength');
    const enableLimitText = $textArea.prop('enableLimitText');
    const bxMaxLength = $textArea.prop('bxmaxLength');

    let isSelectedAll = false;

    // placeholder 를 설정한다.
    UTIL.setIE9PlaceHolder($textArea);

    // 각 이벤트 바인딩
    $textArea.focus(e => {
        $bxInputWrap.addClass(TEXTAREA_SELECTOR.focus);
    });

    $textArea.blur(e => {

        $bxInputWrap.removeClass(TEXTAREA_SELECTOR.focus);

        _limitedText(e);
    });

    $textArea.keydown(e => {

        isSelectedAll = false;

        if (UTIL.isIE9() && e.keyCode === 65 && e.ctrlKey) {
            isSelectedAll = true;
            return;
        }

        _limitedText(e);
    });

    $textArea.keyup(e => {

        if (isSelectedAll) return;

        _limitedText(e);
        _refreshCurrentLength($textArea);
    });


    /**
     * 문자열의 최대값에 대한 이벤트 blocking 및 css 적용 함수
     * @param {event} e - event 객체
     * @private
     */
    function _limitedText(e = {}){

        let value = $textArea.val();

        if (!_isDefaultMaxLength(maxLength) && value.length >= maxLength) {

            if (e.type === 'keyup' && UTIL.isIE9()) {
                $textArea.val(value.substr(0, maxLength));
            }
            if (e.keyCode === 13) {
                e.preventDefault();
            }

            $bxTextAreaWrap.addClass(TEXTAREA_SELECTOR.overflow);

            if (e.type === 'keyup') {

                bxMaxLength.call($textArea.get(0), e);
            }
        }
        else {
            $bxTextAreaWrap.removeClass(TEXTAREA_SELECTOR.overflow);
        }

        if (enableLimitText) {
            _refreshCurrentLength($textArea);
        }
    }
}


/**
 * document contentloaded 시, BxTextarea 의 maxLength 값에 대한 초기 값 설정 및 document contentloaded Event 할당 제거 함수
 *
 * @private
 * @memberOf BxTextarea
 */
function _getMaxLength(maxLength = null){

    let ret = null;

    /*
     * 브라우저별 maxLength 기본값
     * modern: -1
     * ie: 2147483647(모든 IE 계열 브라우저)
     */

    if (_.isNull(maxLength)){
        ret = UTIL.isIE() ? DEFAULT_MAX_LENGTH.ie : DEFAULT_MAX_LENGTH.modern;
    }
    else{
        ret = _.toNumber(maxLength);
    }

    return ret;
}

function _isDefaultMaxLength(maxLength = null){

    if (!_.isNumber(maxLength)){
        CONSOLE.prop.throw(BxTextarea, 'maxLength', 'type');
    }

    let ret = false;

    if (UTIL.isIE()){
        ret = DEFAULT_MAX_LENGTH.ie === maxLength;
    }
    else{
        ret = DEFAULT_MAX_LENGTH.modern === maxLength;
    }

    return ret;
}

/**
 * component option 필수 값 세팅 후 반환하는 함수
 *
 * @param {object} 기본값 옵션 객체
 *
 * @return {object} component opts
 *
 * @private
 * @memberOf BxInput
 */
function _setMandatoryOPTS(opts = {}){

    if (!_.isPlainObject(opts)){
        CONSOLE.prop.throw(BxTextarea, 'opts', 'type');
    }

    let attr = opts.attr;

    let id = attr.id;

    if (!id) {
        attr.id = UTIL.uniqueId(TEXTAREA_SELECTOR.bxTextArea);
    }

    let maxLength = _getMaxLength(attr.maxLength);

    // IE9 브라우저는 별도 getter/setter 를 설정한다.
    if (UTIL.isIE9()) {
        opts.maxLength = maxLength;
    }
    else{
        attr.maxLength = maxLength;
    }

    return opts;
}

function _setInactive($elem = null, inactive = null){

    let $bxInputWrap = $elem.parents(`.${TEXTAREA_SELECTOR.bxInputWrap}`);

    if (inactive) {
        $bxInputWrap.addClass(TEXTAREA_SELECTOR.disabled);
    }
    else {
        $bxInputWrap.removeClass(TEXTAREA_SELECTOR.disabled);
    }

    $elem.prop('disabled', inactive);
}

/**
 * currentLength 에 대해 refresh
 *
 * @param {object}[$elem=null]- textarea jquery Instacnce
 * @private
 * @memberOf BxTextarea
 */
function _refreshCurrentLength($elem = null) {

    if (_.isNull($elem)){
        CONSOLE.prop.throw(BxTextarea, '$elem', 'type');
    }

    if (!_.isFunction($elem.get) && !_.isPlainObject($elem)){
        CONSOLE.prop.throw(BxTextarea, '$elem', 'type');
    }

    let elem = $elem.get(0);

    if (!elem.enableLimitText) return;

    let curLength = $elem.val().length;
    let maxLength = elem.maxLength;
    let $spans = $elem.parent().find(`.${TEXTAREA_SELECTOR.charLimit} span`);

    // maxLength 프로퍼티가 설정되지않은 경우
    if (_isDefaultMaxLength(maxLength)) {
        maxLength = '-';
    }

    $spans.get(0).innerText = curLength;
    $spans.get(1).innerText = maxLength;
}

function _getValue($elem = null){

    if (_.isNull($elem)){
        CONSOLE.prop.throw(BxTextarea, '$elem', 'type');
    }

    if (!_.isFunction($elem.get) || !_.isElement($elem.get(0))){
        CONSOLE.prop.throw(BxTextarea, '$elem', 'type');
    }

    return $elem.html().replace(/\s+$/, '');
}

/*
 * ========================================================================================================
 * below function is API function.
 * ========================================================================================================
 */
/**
 * API 설정 함수
 *
 * @param {object} [elem =null]- BxTextarea DOM
 * @private
 * @memberOf BxTextarea
 */
function _setAPI($elem = null){

    let elem = $elem.get(0);

    _.map(APIS, (v, k) => {
        UTIL.setReadOnlyProperty(elem, k, v);
    });
}

/**
 * 문자열의 index 반환 함수
 *
 * @param {string} str - 찾고자 하는 문자열
 * @returns {number} index - 요청한 문자열의 index
 * @alias indexOf
 * @memberOf BxTextarea
 */
function _indexOf(v = ''){

    if (!_.isString(v) || _.isEmpty(v)) {
        CONSOLE.prop.throw(BxTextarea, 'v', 'all');
    }

    return this.value.indexOf(v);
}
/**
 * 문자열 길이 반환 함수
 * @returns {number} length - 문자열 길이 반환
 * @alias getLength
 * @memberOf BxTextarea
 */
function _getLength(){
    return this.value.length;
}

/**
 * 문자열의 byte 반환 함수
 *
 * @returns {number} byte - 전체 문자열의 byte*
 * @alias getByte
 * @memberOf BxTextarea
 */
function _getByte(){

    let str = this.value;
    let i, b, c;

    /* jshint ignore:start */
    for (b = i = 0; c = str.charCodeAt(i++); b += (c >> 11 ? 3 : (c >> 7 ? 2 : 1)));
    /* jshint ignore:end */

    return b;
}

/**
 * BxTextarea value 초기화 함수
 * @return {object} DOM Element
 * @alias reset
 * @memberOf BxTextarea
 */
function _reset(){

    let $elem = $(this);

    $elem.val('');

    _refreshCurrentLength($elem);

    return this;
}

module.exports = BxTextarea;